
"use client";
import { useState, useEffect } from 'react';
import { PageHeader } from '@/components/page-header';
import { getAllUsers, updateUserRole, getVendorsFromFirestore, updateUserStatus } from '@/app/auth/actions'; // Using Firestore actions
import type { UserProfile, Vendor } from '@/types';
import { useToast } from '@/hooks/use-toast';
import { Loader2, ShieldCheck, Store, User, Lock, Crown, Ban, CheckCircle } from 'lucide-react';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Card } from '@/components/ui/card';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { useAppContext } from '@/components/layout/app-content-wrapper';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';

export default function AdminsPage() {
  const { userProfile: currentUserProfile, authLoading } = useAppContext();
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [dataLoading, setDataLoading] = useState(true);
  const { toast } = useToast();

  const isCurrentUserSuperAdmin = currentUserProfile?.role === 'super-admin';

  const fetchAllData = async () => {
      if (!currentUserProfile) return;
      
      const usersResult = await getAllUsers(); // Firestore action
      if (usersResult.success && usersResult.data) {
          const filteredUsers = usersResult.data.filter(user => user.uid !== currentUserProfile.uid);
          setUsers(filteredUsers);
      } else if (!usersResult.success) {
        toast({
          variant: "destructive",
          title: "Failed to load users",
          description: usersResult.message || "Could not fetch user profiles.",
        });
      }

      const vendorsResult = await getVendorsFromFirestore();
      if (vendorsResult.success && vendorsResult.data) {
        setVendors(vendorsResult.data);
      } else {
         toast({
          variant: "destructive",
          title: "Failed to load vendors",
          description: vendorsResult.error || "Could not fetch vendors.",
        });
      }
  };

  useEffect(() => {
    if (!authLoading && isCurrentUserSuperAdmin) {
      const fetchInitialData = async () => {
        setDataLoading(true);
        await fetchAllData();
        setDataLoading(false);
      };
      
      fetchInitialData();
    } else if (!authLoading && !isCurrentUserSuperAdmin) {
        setDataLoading(false);
    }
  }, [authLoading, isCurrentUserSuperAdmin, currentUserProfile, toast]);


  const handleRoleChange = async (userId: string, newRole: 'admin' | 'vendor' | 'user' | 'super-admin', vendorCode?: string) => {
    const result = await updateUserRole(userId, newRole, vendorCode); // Firestore action
    if (result.success) {
      toast({
        title: "Role Updated",
        description: "The user's role has been successfully updated.",
      });
      await fetchAllData();
    } else {
      toast({
        variant: "destructive",
        title: "Update Failed",
        description: result.message || "Could not update the user's role.",
      });
    }
  };
  
  const handleStatusChange = async (userId: string, newStatus: 'active' | 'blocked') => {
      const result = await updateUserStatus(userId, newStatus);
      if (result.success) {
          toast({
              title: "Status Updated",
              description: `User has been ${newStatus === 'blocked' ? 'blocked' : 'unblocked'}.`
          });
          await fetchAllData();
      } else {
          toast({
              variant: "destructive",
              title: "Status Update Failed",
              description: result.message || "Could not update user status."
          });
      }
  };

  const getRoleBadge = (user: UserProfile) => {
    switch (user.role) {
      case 'super-admin':
        return <Badge variant="default" className="bg-amber-500 hover:bg-amber-500"><Crown className="h-3 w-3 mr-1" />Super Admin</Badge>;
      case 'admin':
        return <Badge variant="default" className="bg-primary hover:bg-primary"><ShieldCheck className="h-3 w-3 mr-1" />Admin</Badge>;
      case 'vendor':
        const vendorName = vendors.find(v => v.code === user.vendorCode)?.name || user.vendorCode;
        return <Badge variant="secondary"><Store className="h-3 w-3 mr-1" />Vendor ({vendorName})</Badge>;
      default:
        return <Badge variant="outline"><User className="h-3 w-3 mr-1" />User</Badge>;
    }
  };
  
  if (authLoading) {
      return (
        <div className="flex flex-col h-full">
            <PageHeader
                title="User Management"
                description="Manage roles and permissions for all application users."
            />
            <div className="flex-1 p-4 md:p-6 flex justify-center items-center">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        </div>
      );
  }
  
  if (!isCurrentUserSuperAdmin) {
    return (
        <div className="flex flex-col h-full">
            <PageHeader
                title="User Management"
                description="Manage roles and permissions for all application users."
            />
            <div className="flex-1 p-4 md:p-6 flex flex-col justify-center items-center text-center">
                <Lock className="h-16 w-16 text-destructive mb-4" />
                <h2 className="text-2xl font-bold text-destructive">Access Denied</h2>
                <p className="text-muted-foreground mt-2">You do not have permission to view this page.</p>
            </div>
        </div>
    );
  }

  return (
    <div className="flex flex-col h-full">
      <PageHeader
        title="User Management"
        description="Manage roles and permissions for all application users."
      />
      <div className="flex-1 p-4 md:p-6 overflow-auto">
        {dataLoading ? (
          <div className="flex justify-center items-center h-full">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        ) : (
          <Card className="shadow-lg">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="font-headline">User</TableHead>
                  <TableHead className="font-headline text-center">Current Role</TableHead>
                  <TableHead className="text-right font-headline">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {users.map((user) => (
                  <TableRow 
                    key={user.uid} 
                    className={cn(
                        "font-body hover:bg-muted/50",
                        user.status === 'blocked' && 'bg-destructive/10 text-muted-foreground'
                    )}
                   >
                    <TableCell className="font-medium">
                      <div className="flex items-center gap-3">
                        <Avatar className="h-9 w-9">
                          <AvatarImage src={user.photoURL} alt={user.displayName} data-ai-hint="user avatar"/>
                          <AvatarFallback>{user.displayName?.[0] || 'U'}</AvatarFallback>
                        </Avatar>
                        <div>
                          <span>{user.displayName}</span>
                          <p className="text-xs">{user.email}</p>
                          {user.status === 'blocked' && <Badge variant="destructive" className="mt-1 text-xs">Blocked</Badge>}
                        </div>
                      </div>
                    </TableCell>
                    <TableCell className="text-center">{getRoleBadge(user)}</TableCell>
                    <TableCell className="text-right">
                       <div className="flex justify-end items-center gap-2">
                         {user.role === 'vendor' && (
                            <Select
                                value={user.vendorCode || ''}
                                onValueChange={(vendorCode) => handleRoleChange(user.uid, 'vendor', vendorCode)}
                                disabled={vendors.length === 0}
                            >
                                <SelectTrigger className="w-[180px] h-9">
                                    <SelectValue placeholder="Assign Vendor" />
                                </SelectTrigger>
                                <SelectContent>
                                    {vendors.map(vendor => (
                                        <SelectItem key={vendor.id} value={vendor.code}>{vendor.name}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                         )}
                         <Select
                            value={user.role || 'user'}
                            onValueChange={(value) => handleRoleChange(user.uid, value as 'admin' | 'vendor' | 'user' | 'super-admin', user.vendorCode)}
                          >
                            <SelectTrigger className="w-[140px] ml-auto h-9">
                              <SelectValue placeholder="Select role" />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="user">User</SelectItem>
                              <SelectItem value="vendor">Vendor</SelectItem>
                              <SelectItem value="admin">Admin</SelectItem>
                              <SelectItem value="super-admin">Super Admin</SelectItem>
                            </SelectContent>
                          </Select>
                           <AlertDialog>
                            <AlertDialogTrigger asChild>
                              {user.status === 'blocked' ? (
                                <Button variant="outline" size="sm" className="bg-green-100 dark:bg-green-900 border-green-500 text-green-700 dark:text-green-300 hover:bg-green-200 dark:hover:bg-green-800">
                                  <CheckCircle className="mr-2 h-4 w-4" /> Unblock
                                </Button>
                              ) : (
                                <Button variant="destructive" size="sm">
                                  <Ban className="mr-2 h-4 w-4" /> Block
                                </Button>
                              )}
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                              <AlertDialogHeader>
                                <AlertDialogTitle>Are you sure?</AlertDialogTitle>
                                <AlertDialogDescription>
                                  You are about to {user.status === 'blocked' ? 'unblock' : 'block'} the user: <span className="font-semibold">{user.displayName}</span>. 
                                  {user.status !== 'blocked' && ' They will be unable to log in.'}
                                </AlertDialogDescription>
                              </AlertDialogHeader>
                              <AlertDialogFooter>
                                <AlertDialogCancel>Cancel</AlertDialogCancel>
                                <AlertDialogAction onClick={() => handleStatusChange(user.uid, user.status === 'blocked' ? 'active' : 'blocked')}>
                                  Confirm
                                </AlertDialogAction>
                              </AlertDialogFooter>
                            </AlertDialogContent>
                          </AlertDialog>
                       </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Card>
        )}
      </div>
    </div>
  );
}
